// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function balanceOf(address) external view returns (uint256);
    function transfer(address, uint256) external returns (bool);
    function transferFrom(address, address, uint256) external returns (bool);
    function approve(address, uint256) external returns (bool);
}

contract Vault {
    IERC20 public immutable asset;
    uint256 public totalAssets;
    uint256 public totalShares;
    address public owner;
    bool public paused;
    uint256 public constant LOCK_DURATION = 7 days;
    uint256 public withdrawFeeBps = 50;
    uint256 public constant MAX_FEE_BPS = 1000;

    mapping(address => uint256) public shareBalance;
    mapping(address => uint256) public lastDeposit;
    mapping(address => bool) public allowedDepositors;
    mapping(address => uint256) public depositCount;

    event Deposit(address indexed user, uint256 assets, uint256 shares);
    event Withdraw(address indexed user, uint256 assets, uint256 shares);
    event PauseToggled(bool paused);
    event FeeUpdated(uint256 oldFee, uint256 newFee);
    event DepositorWhitelisted(address indexed user, bool allowed);

    error NotOwner();
    error VaultPaused();
    error ZeroAmount();
    error InsufficientShares();
    error LockNotElapsed();
    error FeeTooHigh();
    error NotWhitelisted();
    error TransferFailed();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier whenNotPaused() {
        if (paused) revert VaultPaused();
        _;
    }

    modifier whenWhitelisted() {
        if (!allowedDepositors[msg.sender]) revert NotWhitelisted();
        _;
    }

    constructor(address _asset) {
        if (_asset == address(0)) revert ZeroAmount();
        asset = IERC20(_asset);
        owner = msg.sender;
    }

    function deposit(uint256 amount) external whenNotPaused whenWhitelisted returns (uint256 shares) {
        if (amount == 0) revert ZeroAmount();
        if (totalShares == 0) {
            shares = amount;
        } else {
            shares = (amount * totalShares) / totalAssets;
        }
        if (!asset.transferFrom(msg.sender, address(this), amount)) revert TransferFailed();
        totalAssets += amount;
        totalShares += shares;
        shareBalance[msg.sender] += shares;
        lastDeposit[msg.sender] = block.timestamp;
        depositCount[msg.sender]++;
        emit Deposit(msg.sender, amount, shares);
    }

    function withdraw(uint256 shares) external returns (uint256 assets) {
        if (shares == 0) revert ZeroAmount();
        if (shareBalance[msg.sender] < shares) revert InsufficientShares();
        if (block.timestamp < lastDeposit[msg.sender] + LOCK_DURATION) revert LockNotElapsed();
        assets = (shares * totalAssets) / totalShares;
        uint256 fee = (assets * withdrawFeeBps) / 10000;
        uint256 payout = assets - fee;
        shareBalance[msg.sender] -= shares;
        totalShares -= shares;
        totalAssets -= assets;
        if (!asset.transfer(msg.sender, payout)) revert TransferFailed();
        if (fee > 0) {
            if (!asset.transfer(owner, fee)) revert TransferFailed();
        }
        emit Withdraw(msg.sender, assets, shares);
    }

    function previewDeposit(uint256 amount) external view returns (uint256) {
        if (totalShares == 0) return amount;
        return (amount * totalShares) / totalAssets;
    }

    function previewWithdraw(uint256 shares) external view returns (uint256) {
        if (totalShares == 0) return 0;
        uint256 assets = (shares * totalAssets) / totalShares;
        uint256 fee = (assets * withdrawFeeBps) / 10000;
        return assets - fee;
    }

    function setPaused(bool _paused) external onlyOwner {
        paused = _paused;
        emit PauseToggled(_paused);
    }

    function setWithdrawFee(uint256 newFeeBps) external onlyOwner {
        if (newFeeBps > MAX_FEE_BPS) revert FeeTooHigh();
        emit FeeUpdated(withdrawFeeBps, newFeeBps);
        withdrawFeeBps = newFeeBps;
    }

    function whitelistDepositor(address user, bool allowed) external onlyOwner {
        allowedDepositors[user] = allowed;
        emit DepositorWhitelisted(user, allowed);
    }

    function emergencyWithdraw(address to, uint256 amount) external onlyOwner {
        if (!asset.transfer(to, amount)) revert TransferFailed();
    }

    function transferOwnership(address newOwner) external onlyOwner {
        if (newOwner == address(0)) revert ZeroAmount();
        owner = newOwner;
    }

    function pricePerShare() external view returns (uint256) {
        if (totalShares == 0) return 1e18;
        return (totalAssets * 1e18) / totalShares;
    }
}
